            toStringOutput.Add($"Segments = {(this.Segments == null ? "null" : $"[{string.Join(", ", this.Segments)} ]")}");
            toStringOutput.Add($"Priority = {(this.Priority == null ? "null" : this.Priority.ToString())}");
            toStringOutput.Add($"Ttl = {(this.Ttl == null ? "null" : this.Ttl.ToString())}");
            toStringOutput.Add($"Title = {this.Title ?? "null"}");
            toStringOutput.Add($"Body = {this.Body ?? "null"}");
            toStringOutput.Add($"Sound = {this.Sound ?? "null"}");
            toStringOutput.Add($"Action = {this.Action ?? "null"}");
            toStringOutput.Add($"Data = {(this.Data == null ? "null" : this.Data.ToString())}");
            toStringOutput.Add($"Apn = {(this.Apn == null ? "null" : this.Apn.ToString())}");
            toStringOutput.Add($"Gcm = {(this.Gcm == null ? "null" : this.Gcm.ToString())}");
            toStringOutput.Add($"Fcm = {(this.Fcm == null ? "null" : this.Fcm.ToString())}");
            toStringOutput.Add($"Sms = {(this.Sms == null ? "null" : this.Sms.ToString())}");
            toStringOutput.Add($"FacebookMessenger = {(this.FacebookMessenger == null ? "null" : this.FacebookMessenger.ToString())}");
            toStringOutput.Add($"Alexa = {(this.Alexa == null ? "null" : this.Alexa.ToString())}");

            additionalProperties?
                .Select(kvp => $"[{kvp.Key}] = {kvp.Value.ToString(Formatting.None)}")
                .ToList()
                .ForEach(toStringOutput.Add);
        }
    }
}